function openPDF(title, subtitle, sections) {
  const css = `*{box-sizing:border-box;margin:0;padding:0}body{font-family:'Segoe UI',Arial,sans-serif;padding:28px;color:#0f172a;font-size:13px}.cover{text-align:center;padding:30px 0 20px;border-bottom:3px solid #6366f1;margin-bottom:24px}.cover h1{font-size:26px;font-weight:900;color:#6366f1}.section{margin-bottom:30px}.section-title{font-size:15px;font-weight:800;color:#4f46e5;padding:10px 14px;background:#f0f0ff;border-left:4px solid #6366f1;border-radius:4px;margin-bottom:12px}.summary-row{display:flex;gap:12px;margin-bottom:16px;flex-wrap:wrap}.summary-card{flex:1;min-width:120px;padding:12px 16px;border-radius:12px;text-align:center}.summary-card .val{font-size:18px;font-weight:900}.summary-card .lbl{font-size:10px;margin-top:3px;text-transform:uppercase}table{width:100%;border-collapse:collapse;font-size:11.5px}th{background:#0f172a;color:#fff;padding:9px 10px;text-align:left;font-size:11px;font-weight:700;text-transform:uppercase}td{padding:8px 10px;border-bottom:1px solid #e9ecef}tr:nth-child(even) td{background:#f8fafc}.badge{padding:2px 9px;border-radius:20px;font-size:10px;font-weight:700}.badge-pago{background:#d1fae5;color:#065f46}.badge-parcial{background:#dbeafe;color:#1e40af}.badge-pendente{background:#fef3c7;color:#92400e}.badge-atrasado{background:#fee2e2;color:#991b1b}.footer{text-align:center;font-size:10px;color:#aaa;border-top:1px solid #e9ecef;padding-top:14px;margin-top:24px}`;
  const now = new Date().toLocaleString("pt-BR");
  const html = `<!DOCTYPE html><html><head><meta charset="utf-8"><title>${title}</title><style>${css}</style></head><body><div class="cover"><h1>📡 RB Sistema</h1><h2 style="font-size:18px;color:#0f172a;margin:8px 0 4px">${title}</h2><p>${subtitle}</p><p style="margin-top:6px;font-size:11px">Gerado em ${now}</p></div>${sections.join("")}<div class="footer">RB Sistema — ${now}</div><script>window.onload=()=>setTimeout(()=>window.print(),400)<\/script></body></html>`;
  dlFile(
    html,
    `${
      title
        .replace(/[^\w\s]/g, "")
        .trim()
        .replace(/\s+/g, "_") || "relatorio"
    }.html`,
    "text/html;charset=utf-8",
  );
}
function buildSummaryRow(cards) {
  return `<div class="summary-row">${cards.map((c) => `<div class="summary-card" style="background:${c.bg}"><div class="val" style="color:${c.tc}">${c.val}</div><div class="lbl" style="color:${c.tc}">${c.lbl}</div></div>`).join("")}</div>`;
}
function badgeHtml(s) {
  return `<span class="badge badge-${s}">${{ pago: "✅ Pago", parcial: "🔵 Parcial", pendente: "⏳ Pendente", atrasado: "🔴 Atrasado" }[s] || s}</span>`;
}
