function pdfDevedores(oiClients, groups, m) {
  const devedores = oiClients
    .filter((c) =>
      ["pendente", "atrasado", "parcial"].includes(getPayStatus(c, m)),
    )
    .map((c) => {
      const st = getPayStatus(c, m);
      const po = getPayObj(c, m);
      const debt = st === "parcial" ? po?.remaining || 0 : c.monthlyValue;
      return { ...c, status: st, debt };
    })
    .sort((a, b) => b.debt - a.debt);
  const total = devedores.reduce((s, c) => s + c.debt, 0);
  const groupMap = {};
  groups.forEach((g) => {
    groupMap[g.id] = g.responsible;
  });
  const summary = buildSummaryRow([
    { val: devedores.length, lbl: "Devedores", bg: "#fee2e2", tc: "#991b1b" },
    { val: fmtMoney(total), lbl: "Total Aberto", bg: "#fef3c7", tc: "#92400e" },
  ]);
  const tRows = devedores
    .map(
      (c, i) =>
        `<tr><td style="text-align:center;font-weight:900;color:#6366f1">#${i + 1}</td><td style="font-weight:700">${c.name}</td><td>${c.caid || "—"}</td><td>${c.phone || "—"}</td><td>${c.cpf || "—"}</td><td>Dia ${c.dueDate}</td><td style="font-weight:700;color:#dc2626">${fmtMoney(c.debt)}</td><td>${badgeHtml(c.status)}</td><td>${groupMap[c.groupId] || "—"}</td></tr>`,
    )
    .join("");
  openPDF(`Ranking de Devedores`, `Mês: ${fmtMonth(m)}`, [
    `<div class="section"><div class="section-title">🔴 Devedores — ${fmtMonth(m)}</div>${summary}<table><thead><tr><th>#</th><th>Nome</th><th>CAID</th><th>Telefone</th><th>CPF</th><th>Venc.</th><th>Débito</th><th>Status</th><th>Grupo</th></tr></thead><tbody>${tRows}</tbody></table></div>`,
  ]);
}
function pdfGrupos(groups, oiClients, m) {
  const groupRows = groups.map((g) => {
    const gc = oiClients.filter((c) => String(c.groupId) === String(g.id));
    const totalV = gc.reduce((s, c) => s + c.monthlyValue, 0);
    const totalP = gc.reduce(
      (s, c) => s + (getPayStatus(c, m) === "pago" ? c.monthlyValue : 0),
      0,
    );
    const parcV = gc.reduce((s, c) => {
      const po = getPayObj(c, m);
      return s + (getPayStatus(c, m) === "parcial" && po?.paid ? po.paid : 0);
    }, 0);
    return {
      g,
      gc,
      totalV,
      totalP,
      parcV,
      pend: Math.max(0, totalV - totalP - parcV),
    };
  });
  const totalGeral = groupRows.reduce((s, r) => s + r.totalV, 0);
  const totalPago = groupRows.reduce((s, r) => s + r.totalP + r.parcV, 0);
  const summary = buildSummaryRow([
    { val: groups.length, lbl: "Grupos", bg: "#ede9fe", tc: "#5b21b6" },
    {
      val: fmtMoney(totalGeral),
      lbl: "Valor Total",
      bg: "#dbeafe",
      tc: "#1e40af",
    },
    { val: fmtMoney(totalPago), lbl: "Recebido", bg: "#d1fae5", tc: "#065f46" },
  ]);
  const groupSections = groupRows
    .map(({ g, gc, totalV, totalP, parcV, pend }) => {
      const clientRows = gc
        .map(
          (c) =>
            `<tr><td style="font-weight:600">${c.name}</td><td>${c.caid || "—"}</td><td>${c.cpf || "—"}</td><td>${c.phone || "—"}</td><td>Dia ${c.dueDate}</td><td>${fmtMoney(c.monthlyValue)}</td><td>${badgeHtml(getPayStatus(c, m))}</td></tr>`,
        )
        .join("");
      return `<div class="section"><h3>${g.responsible}</h3><table><thead><tr><th>Nome</th><th>CAID</th><th>CPF</th><th>Telefone</th><th>Venc.</th><th>Valor</th><th>Status</th></tr></thead><tbody>${clientRows}</tbody></table></div>`;
    })
    .join("");
  openPDF(`Relatório de Grupos OI TV`, `Mês: ${fmtMonth(m)}`, [
    `<div class="section"><div class="section-title">📊 Resumo</div>${summary}</div>`,
    groupSections,
  ]);
}
function pdfRbClientes(rbClients, sales) {
  const clientRows = rbClients
    .map((c) => {
      const cs = sales.filter((s) => s.clientName === c.name);
      const ct = cs.reduce((s, v) => s + v.value, 0);
      return `<tr><td style="font-weight:700">${c.name}</td><td>${c.phone || "—"}</td><td>${c.email || "—"}</td><td style="text-align:center">${cs.length}</td><td style="font-weight:700;color:#065f46">${fmtMoney(ct)}</td></tr>`;
    })
    .join("");
  openPDF(`Relatório RB Revendas`, `${rbClients.length} clientes`, [
    `<div class="section"><div class="section-title">👥 Clientes</div><table><thead><tr><th>Nome</th><th>Telefone</th><th>E-mail</th><th>Compras</th><th>Total</th></tr></thead><tbody>${clientRows}</tbody></table></div>`,
  ]);
}

