// ── Restore Prompt ────────────────────────────────────────────
function RestorePrompt({ onRestore, onSkip }) {
  const [msg, setMsg] = useState(null),
    fRef = useRef();
  function handleFile(e) {
    const file = e.target.files[0];
    if (!file) return;
    const r = new FileReader();
    r.onload = (ev) => {
      try {
        const d = JSON.parse(ev.target.result);
        if (!d.version) throw new Error("Arquivo inválido.");
        onRestore(d);
        setMsg({ ok: true, text: "✅ Restaurado!" });
        setTimeout(() => onSkip(), 1400);
      } catch (err) {
        setMsg({ ok: false, text: `❌ ${err.message}` });
      }
      e.target.value = "";
    };
    r.readAsText(file, "utf-8");
  }
  return (
    <div
      style={{
        minHeight: "100vh",
        background: "linear-gradient(180deg,#0f172a,#1e1b4b)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: 20,
      }}
    >
      <div
        style={{
          background: "rgba(255,255,255,0.07)",
          backdropFilter: "blur(20px)",
          border: "1px solid rgba(255,255,255,0.12)",
          borderRadius: 28,
          padding: 48,
          maxWidth: 440,
          width: "100%",
          textAlign: "center",
        }}
      >
        <div
          style={{
            width: 72,
            height: 72,
            borderRadius: 20,
            background: G.success,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontSize: 30,
            margin: "0 auto 20px",
          }}
        >
          🛡️
        </div>
        <h2
          style={{
            margin: "0 0 10px",
            fontSize: 22,
            fontWeight: 800,
            color: "#fff",
          }}
        >
          Restaurar Backup?
        </h2>
        <p
          style={{
            margin: "0 0 32px",
            color: "rgba(255,255,255,0.5)",
            fontSize: 14,
          }}
        >
          Carregar dados de um backup anterior?
        </p>
        <input
          ref={fRef}
          type="file"
          accept=".json"
          onChange={handleFile}
          style={{ display: "none" }}
        />
        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          <button
            onClick={() => fRef.current.click()}
            style={{
              padding: 14,
              background: "linear-gradient(135deg,#6366f1,#8b5cf6)",
              color: "#fff",
              border: "none",
              borderRadius: 12,
              fontSize: 15,
              fontWeight: 700,
              cursor: "pointer",
              fontFamily: "inherit",
            }}
          >
            📂 Selecionar Backup (.json)
          </button>
          <button
            onClick={onSkip}
            style={{
              padding: 13,
              background: "rgba(255,255,255,0.08)",
              color: "rgba(255,255,255,0.7)",
              border: "1px solid rgba(255,255,255,0.15)",
              borderRadius: 12,
              fontSize: 14,
              cursor: "pointer",
              fontFamily: "inherit",
            }}
          >
            Continuar sem restaurar
          </button>
        </div>
        {msg && (
          <div
            style={{
              marginTop: 20,
              padding: "12px 16px",
              borderRadius: 12,
              background: msg.ok
                ? "rgba(16,185,129,0.2)"
                : "rgba(239,68,68,0.2)",
              color: msg.ok ? "#6ee7b7" : "#fca5a5",
              fontWeight: 600,
              fontSize: 13,
            }}
          >
            {msg.text}
          </div>
        )}
      </div>
    </div>
  );
}

