// ── Financeiro Page ───────────────────────────────────────────
function FinanceiroPage({ oiClients, sales, filterMonth, setFilterMonth, C }) {
  const rec = oiClients.reduce(
    (s, c) =>
      s + (getPayStatus(c, filterMonth) === "pago" ? c.monthlyValue : 0),
    0,
  );
  const parcial = oiClients.reduce((s, c) => {
    const po = getPayObj(c, filterMonth);
    return (
      s + (getPayStatus(c, filterMonth) === "parcial" && po?.paid ? po.paid : 0)
    );
  }, 0);
  const pend = oiClients.reduce(
    (s, c) =>
      s + (getPayStatus(c, filterMonth) === "pendente" ? c.monthlyValue : 0),
    0,
  );
  const atras = oiClients.reduce(
    (s, c) =>
      s + (getPayStatus(c, filterMonth) === "atrasado" ? c.monthlyValue : 0),
    0,
  );
  const totalV = sales.reduce((s, v) => s + v.value, 0);
  const byPay = {};
  sales.forEach((s) => {
    byPay[s.payment] = (byPay[s.payment] || 0) + s.value;
  });
  return (
    <div style={{ animation: "fadeIn 0.3s" }}>
      <div
        style={{
          display: "flex",
          gap: 10,
          alignItems: "center",
          marginBottom: 24,
          flexWrap: "wrap",
        }}
      >
        <label style={{ fontWeight: 600, fontSize: 13, color: C.muted }}>
          Mês:
        </label>
        <select
          value={filterMonth}
          onChange={(e) => setFilterMonth(e.target.value)}
          className="rb-input"
          style={{
            padding: "9px 14px",
            border: `1.5px solid ${C.border}`,
            borderRadius: 10,
            fontSize: 14,
            background: C.inputBg,
            color: C.text,
            outline: "none",
            fontFamily: "inherit",
          }}
        >
          {MONTHS.map((m) => (
            <option key={m} value={m}>
              {fmtMonth(m)}
            </option>
          ))}
        </select>
        <Btn
          variant="export"
          size="sm"
          onClick={() => exportFinCsv(oiClients, sales, filterMonth)}
          C={C}
        >
          ⬇️ CSV
        </Btn>
      </div>
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(auto-fit,minmax(180px,1fr))",
          gap: 16,
          marginBottom: 24,
        }}
      >
        <StatCard
          label="Recebido OI TV"
          value={fmtMoney(rec)}
          icon="✅"
          gradient={G.success}
          C={C}
        />
        <StatCard
          label="Parcial"
          value={fmtMoney(parcial)}
          icon="🔵"
          gradient={G.info}
          C={C}
        />
        <StatCard
          label="Pendente"
          value={fmtMoney(pend)}
          icon="⏳"
          gradient={G.warning}
          C={C}
        />
        <StatCard
          label="Atrasado"
          value={fmtMoney(atras)}
          icon="🔴"
          gradient={G.danger}
          C={C}
        />
        <StatCard
          label="Total RB"
          value={fmtMoney(totalV)}
          icon="🛒"
          gradient={G.purple}
          C={C}
        />
      </div>
      <div style={{ display: "grid", gridTemplateColumns: "3fr 2fr", gap: 20 }}>
        <Card C={C}>
          <CardHeader
            title={`OI TV — ${fmtMonth(filterMonth)}`}
            icon="📺"
            C={C}
          />
          <div style={{ padding: 24, maxHeight: 480, overflowY: "auto" }}>
            {oiClients.map((c) => {
              const st = getPayStatus(c, filterMonth);
              const po = getPayObj(c, filterMonth);
              return (
                <div
                  key={c.id}
                  className="rb-row"
                  style={{
                    display: "flex",
                    justifyContent: "space-between",
                    alignItems: "center",
                    padding: "11px 0",
                    borderBottom: `1px solid ${C.border}`,
                  }}
                >
                  <div>
                    <div
                      style={{ fontSize: 14, fontWeight: 600, color: C.text }}
                    >
                      {c.name}
                    </div>
                    {c.caid && (
                      <div
                        style={{ fontSize: 11, color: C.muted, marginTop: 1 }}
                      >
                        CAID: {c.caid}
                      </div>
                    )}
                  </div>
                  <div
                    style={{ display: "flex", alignItems: "center", gap: 10 }}
                  >
                    <span
                      style={{ fontSize: 13, fontWeight: 700, color: C.text }}
                    >
                      {fmtMoney(c.monthlyValue)}
                    </span>
                    <StatusBadge status={st} C={C} />
                  </div>
                </div>
              );
            })}
          </div>
        </Card>
        <Card C={C}>
          <CardHeader title="Formas de Pgto — RB" icon="💳" C={C} />
          <div style={{ padding: 24 }}>
            {Object.entries(byPay).map(([k, v]) => (
              <div
                key={k}
                style={{
                  display: "flex",
                  justifyContent: "space-between",
                  padding: "12px 0",
                  borderBottom: `1px solid ${C.border}`,
                }}
              >
                <span
                  style={{
                    fontSize: 14,
                    textTransform: "uppercase",
                    fontWeight: 600,
                    color: C.muted,
                  }}
                >
                  {k}
                </span>
                <span style={{ fontSize: 15, fontWeight: 800, color: C.text }}>
                  {fmtMoney(v)}
                </span>
              </div>
            ))}
            {Object.keys(byPay).length === 0 && (
              <p style={{ color: C.muted, fontSize: 14 }}>Nenhuma venda.</p>
            )}
            <div
              style={{
                marginTop: 14,
                padding: 16,
                borderRadius: 14,
                background: C.successLight,
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
              }}
            >
              <span style={{ fontWeight: 700, color: C.successDark }}>
                TOTAL
              </span>
              <span
                style={{ fontSize: 20, fontWeight: 900, color: C.successDark }}
              >
                {fmtMoney(totalV)}
              </span>
            </div>
          </div>
        </Card>
      </div>
    </div>
  );
}

