// ── Nav Config ────────────────────────────────────────────────
const NAV = [
  { key: "dashboard", icon: "⊞", label: "Dashboard" },
  { key: "oitv", icon: "📺", label: "OI TV" },
  { key: "grupos", icon: "👥", label: "Grupos OI TV" },
  { key: "rbrevendas", icon: "🛒", label: "RB Revendas" },
  { key: "loja", icon: "🏪", label: "Loja Pública" },
  { key: "produtos", icon: "📦", label: "Produtos" },
  { key: "financeiro", icon: "💰", label: "Financeiro" },
  { key: "relatorios", icon: "📋", label: "Relatórios" },
  { key: "configuracoes", icon: "⚙️", label: "Configurações" },
];

// ── App ───────────────────────────────────────────────────────
export default function App() {
  const [auth, setAuth] = useState(null),
    [page, setPage] = useState("dashboard");
  const [oiClients, setOiRaw] = useState([]),
    [groups, setGroupsRaw] = useState([]),
    [rbClients, setRbRaw] = useState([]),
    [products, setProductsRaw] = useState([]),
    [sales, setSalesRaw] = useState([]);
  const [filterMonth, setFilterMonth] = useState(currentMonth()),
    [loaded, setLoaded] = useState(false),
    [showRestore, setShowRestore] = useState(false);

  // Theme state — load from personal storage
  const [darkMode, setDarkModeRaw] = useState(false);
  const [themeName, setThemeNameRaw] = useState("indigo");
  const [sidebarOpen, setSidebarOpenRaw] = useState(true);

  const C = makeColors(themeName, darkMode);

  useEffect(() => {
    (async () => {
      const [oi, gr, rb, pr, sa] = await Promise.all([
        storeGet("oiClients"),
        storeGet("groups"),
        storeGet("rbClients"),
        storeGet("products"),
        storeGet("sales"),
      ]);
      if (oi) setOiRaw(oi);
      if (gr) setGroupsRaw(gr);
      if (rb) setRbRaw(rb);
      if (pr) setProductsRaw(pr);
      if (sa) setSalesRaw(sa);
      // Load personal preferences (non-shared)
      try {
        const pref = await window.storage.get("userPrefs");
        if (pref) {
          const p = JSON.parse(pref.value);
          if (p.darkMode !== undefined) setDarkModeRaw(p.darkMode);
          if (p.themeName) setThemeNameRaw(p.themeName);
          if (p.sidebarOpen !== undefined) setSidebarOpenRaw(p.sidebarOpen);
        }
      } catch {}
      setLoaded(true);
    })();
  }, []);

  function savePrefs(prefs) {
    window.storage.set("userPrefs", JSON.stringify(prefs)).catch(() => {});
  }
  function setDarkMode(v) {
    setDarkModeRaw(v);
    savePrefs({ darkMode: v, themeName, sidebarOpen });
  }
  function setThemeName(v) {
    setThemeNameRaw(v);
    savePrefs({ darkMode, themeName: v, sidebarOpen });
  }
  function setSidebarOpen(v) {
    setSidebarOpenRaw(v);
    savePrefs({ darkMode, themeName, sidebarOpen: v });
  }

  const setOiClients = (v) => {
    const n = typeof v === "function" ? v(oiClients) : v;
    setOiRaw(n);
    storeSet("oiClients", n);
  };
  const setGroups = (v) => {
    const n = typeof v === "function" ? v(groups) : v;
    setGroupsRaw(n);
    storeSet("groups", n);
  };
  const setRbClients = (v) => {
    const n = typeof v === "function" ? v(rbClients) : v;
    setRbRaw(n);
    storeSet("rbClients", n);
  };
  const setProducts = (v) => {
    const n = typeof v === "function" ? v(products) : v;
    setProductsRaw(n);
    storeSet("products", n);
  };
  const setSales = (v) => {
    const n = typeof v === "function" ? v(sales) : v;
    setSalesRaw(n);
    storeSet("sales", n);
  };
  function restoreBackup(data) {
    if (data.oiClients) setOiClients(data.oiClients);
    if (data.groups) setGroups(data.groups);
    if (data.rbClients) setRbClients(data.rbClients);
    if (data.products) setProducts(data.products);
    if (data.sales) setSales(data.sales);
  }
  function handleLogin(email, pass) {
    const admin = ADMINS.find((a) => a.email === email && a.password === pass);
    if (admin) {
      setAuth({ email, role: "admin", name: admin.name });
      setShowRestore(true);
    } else if (email && pass) setAuth({ email, role: "user", name: email });
    else alert("Credenciais inválidas");
  }

  if (!loaded)
    return (
      <div
        style={{
          minHeight: "100vh",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          background: "linear-gradient(180deg,#0f172a,#1e1b4b)",
          flexDirection: "column",
          gap: 16,
          fontFamily: "'Inter',system-ui,sans-serif",
        }}
      >
        <div
          style={{
            width: 60,
            height: 60,
            borderRadius: 18,
            background: "linear-gradient(135deg,#6366f1,#8b5cf6)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontSize: 28,
            animation: "pulse 1.5s infinite",
          }}
        >
          📡
        </div>
        <div style={{ color: "rgba(255,255,255,0.5)", fontSize: 14 }}>
          Carregando...
        </div>
      </div>
    );

  if (!auth)
    return (
      <>
        <GlobalStyles C={C} dark={darkMode} />
        <LoginPage onLogin={handleLogin} />
      </>
    );
  if (auth.role !== "admin")
    return (
      <>
        <GlobalStyles C={C} dark={darkMode} />
        <PublicStore products={products} onLogout={() => setAuth(null)} />
      </>
    );
  if (showRestore)
    return (
      <>
        <GlobalStyles C={C} dark={darkMode} />
        <RestorePrompt
          onRestore={(d) => {
            restoreBackup(d);
            setShowRestore(false);
          }}
          onSkip={() => setShowRestore(false)}
        />
      </>
    );

  const totalRecMes = oiClients.reduce(
    (s, c) =>
      s + (getPayStatus(c, filterMonth) === "pago" ? c.monthlyValue : 0),
    0,
  );
  const totalPendMes = oiClients.reduce(
    (s, c) =>
      s + (getPayStatus(c, filterMonth) !== "pago" ? c.monthlyValue : 0),
    0,
  );
  const currentNav = NAV.find((n) => n.key === page);

  return (
    <div
      style={{
        display: "flex",
        minHeight: "100vh",
        fontFamily: "'Inter','Segoe UI',system-ui,sans-serif",
        background: C.bg,
        transition: "background 0.3s",
      }}
    >
      <GlobalStyles C={C} dark={darkMode} />

      {/* Sidebar */}
      <aside
        style={{
          width: sidebarOpen ? 260 : 72,
          background: C.gradientSidebar,
          flexShrink: 0,
          display: "flex",
          flexDirection: "column",
          transition: "width 0.3s cubic-bezier(0.4,0,0.2,1)",
          overflow: "hidden",
          position: "sticky",
          top: 0,
          height: "100vh",
          zIndex: 200,
        }}
      >
        <div
          style={{
            padding: "20px 16px",
            display: "flex",
            alignItems: "center",
            gap: 12,
            cursor: "pointer",
            borderBottom: "1px solid rgba(255,255,255,0.06)",
          }}
          onClick={() => setSidebarOpen(!sidebarOpen)}
        >
          <div
            style={{
              width: 40,
              height: 40,
              borderRadius: 12,
              background: C.gradientPrimary,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              fontSize: 18,
              flexShrink: 0,
            }}
          >
            📡
          </div>
          {sidebarOpen && (
            <div>
              <div style={{ color: "#fff", fontWeight: 800, fontSize: 15 }}>
                RB Sistema
              </div>
              <div style={{ color: "rgba(255,255,255,0.35)", fontSize: 11 }}>
                v2.1 · Admin
              </div>
            </div>
          )}
        </div>
        <nav style={{ flex: 1, padding: "12px 10px", overflowY: "auto" }}>
          {NAV.map((n) => {
            const isActive = page === n.key;
            return (
              <div
                key={n.key}
                className="nav-item"
                onClick={() => setPage(n.key)}
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: 12,
                  padding: "10px 12px",
                  borderRadius: 12,
                  cursor: "pointer",
                  marginBottom: 4,
                  background: isActive ? `${C.primary}33` : "transparent",
                  borderLeft: isActive
                    ? `3px solid ${C.primary}`
                    : `3px solid transparent`,
                  whiteSpace: "nowrap",
                }}
              >
                <span style={{ fontSize: 17, flexShrink: 0 }}>{n.icon}</span>
                {sidebarOpen && (
                  <span
                    style={{
                      fontSize: 13,
                      fontWeight: isActive ? 700 : 500,
                      color: isActive ? "#fff" : "rgba(255,255,255,0.6)",
                    }}
                  >
                    {n.label}
                  </span>
                )}
              </div>
            );
          })}
        </nav>
        <div
          style={{
            padding: "14px",
            borderTop: "1px solid rgba(255,255,255,0.06)",
          }}
        >
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: 10,
              marginBottom: 10,
            }}
          >
            <div
              style={{
                width: 36,
                height: 36,
                borderRadius: 10,
                background: C.gradientPrimary,
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                fontSize: 15,
                fontWeight: 800,
                color: "#fff",
                flexShrink: 0,
              }}
            >
              {auth.name[0]}
            </div>
            {sidebarOpen && (
              <div>
                <div style={{ color: "#fff", fontSize: 13, fontWeight: 600 }}>
                  {auth.name}
                </div>
                <div style={{ color: "rgba(255,255,255,0.35)", fontSize: 11 }}>
                  Administrador
                </div>
              </div>
            )}
          </div>
          <button
            onClick={() => setAuth(null)}
            style={{
              width: "100%",
              padding: "8px",
              background: "rgba(255,255,255,0.07)",
              color: "rgba(255,255,255,0.5)",
              border: "1px solid rgba(255,255,255,0.1)",
              borderRadius: 10,
              cursor: "pointer",
              fontSize: 12,
              fontFamily: "inherit",
              fontWeight: 500,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              gap: 6,
            }}
          >
            {sidebarOpen ? "↩ Sair" : "↩"}
          </button>
        </div>
      </aside>

      {/* Main */}
      <div
        style={{
          flex: 1,
          display: "flex",
          flexDirection: "column",
          overflow: "auto",
          minWidth: 0,
        }}
      >
        <header
          style={{
            background: C.card,
            padding: "0 28px",
            borderBottom: `1px solid ${C.border}`,
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
            height: 64,
            position: "sticky",
            top: 0,
            zIndex: 100,
            boxShadow: shadow.sm,
            flexShrink: 0,
            transition: "background 0.3s",
          }}
        >
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <span style={{ fontSize: 18 }}>{currentNav?.icon}</span>
            <h1
              style={{
                margin: 0,
                fontSize: 17,
                fontWeight: 700,
                color: C.text,
              }}
            >
              {currentNav?.label}
            </h1>
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
            {/* Dark mode quick toggle */}
            <button
              onClick={() => setDarkMode(!darkMode)}
              style={{
                background: C.inputBg,
                border: `1px solid ${C.border}`,
                borderRadius: 10,
                padding: "7px 12px",
                cursor: "pointer",
                fontSize: 16,
                color: C.text,
                fontFamily: "inherit",
                display: "flex",
                alignItems: "center",
                gap: 6,
              }}
              title="Alternar modo escuro"
            >
              {darkMode ? "☀️" : "🌙"}
            </button>
            <span
              style={{
                fontSize: 12,
                color: C.muted,
                display: "flex",
                alignItems: "center",
                gap: 6,
              }}
            >
              <span
                style={{
                  width: 7,
                  height: 7,
                  borderRadius: "50%",
                  background: C.success,
                  display: "inline-block",
                }}
              />
              {new Date().toLocaleDateString("pt-BR", {
                weekday: "short",
                day: "numeric",
                month: "short",
              })}
            </span>
            <div
              style={{
                width: 34,
                height: 34,
                borderRadius: 10,
                background: C.gradientPrimary,
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                fontSize: 14,
                fontWeight: 800,
                color: "#fff",
              }}
            >
              {auth.name[0]}
            </div>
          </div>
        </header>
        <main style={{ flex: 1, padding: 28, overflowY: "auto" }}>
          {page === "dashboard" && (
            <DashboardPage
              oiClients={oiClients}
              groups={groups}
              rbClients={rbClients}
              sales={sales}
              filterMonth={filterMonth}
              setFilterMonth={setFilterMonth}
              totalRecMes={totalRecMes}
              totalPendMes={totalPendMes}
              setPage={setPage}
              userName={auth.name}
              C={C}
            />
          )}
          {page === "oitv" && (
            <OiTvPage
              clients={oiClients}
              setClients={setOiClients}
              groups={groups}
              filterMonth={filterMonth}
              setFilterMonth={setFilterMonth}
              C={C}
            />
          )}
          {page === "grupos" && (
            <GroupsPage
              groups={groups}
              setGroups={setGroups}
              clients={oiClients}
              setClients={setOiClients}
              filterMonth={filterMonth}
              C={C}
            />
          )}
          {page === "rbrevendas" && (
            <RbRevendasPage
              clients={rbClients}
              setClients={setRbClients}
              sales={sales}
              setSales={setSales}
              C={C}
            />
          )}
          {page === "loja" && <PublicStore products={products} />}
          {page === "produtos" && (
            <ProductsPage products={products} setProducts={setProducts} C={C} />
          )}
          {page === "financeiro" && (
            <FinanceiroPage
              oiClients={oiClients}
              sales={sales}
              filterMonth={filterMonth}
              setFilterMonth={setFilterMonth}
              C={C}
            />
          )}
          {page === "relatorios" && (
            <RelatoriosPage
              oiClients={oiClients}
              groups={groups}
              rbClients={rbClients}
              sales={sales}
              filterMonth={filterMonth}
              setFilterMonth={setFilterMonth}
              C={C}
            />
          )}
          {page === "configuracoes" && (
            <ConfiguracoesPage
              C={C}
              darkMode={darkMode}
              setDarkMode={setDarkMode}
              themeName={themeName}
              setThemeName={setThemeName}
              sidebarOpen={sidebarOpen}
              setSidebarOpen={setSidebarOpen}
              oiClients={oiClients}
              groups={groups}
              rbClients={rbClients}
              products={products}
              sales={sales}
              filterMonth={filterMonth}
              onRestore={restoreBackup}
              auth={auth}
            />
          )}
        </main>
      </div>
    </div>
  );
}
